import{_ as e,o as t,c as o,ae as r}from"./chunks/framework.9mFzz-eW.js";const h=JSON.parse('{"title":"V8 엔진 최적화 전략 ⭐️","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/v8-optimization.md","filePath":"architecture/v8-optimization.md"}'),i={name:"architecture/v8-optimization.md"};function c(n,a,l,p,d,s){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="v8-엔진-최적화-전략-⭐️" tabindex="-1">V8 엔진 최적화 전략 ⭐️ <a class="header-anchor" href="#v8-엔진-최적화-전략-⭐️" aria-label="Permalink to &quot;V8 엔진 최적화 전략 ⭐️&quot;">​</a></h1><p>DSM은 단순한 상태 관리 라이브러리가 아닙니다. 자바스크립트 엔진(V8)의 동작 원리, 특히 <strong>JIT(Just-In-Time) 컴파일러와 가비지 컬렉터(GC)를 굴복시킬 수준의 최적화</strong>를 코어에 담았습니다.</p><h2 id="_1-lazy-proxying-weakmap-캐싱" tabindex="-1">1. Lazy-Proxying &amp; WeakMap 캐싱 <a class="header-anchor" href="#_1-lazy-proxying-weakmap-캐싱" aria-label="Permalink to &quot;1. Lazy-Proxying &amp; WeakMap 캐싱&quot;">​</a></h2><p>렌더링 파이프라인 내에서 매번 새로운 <code>Proxy</code>를 동적으로 생성하는 것은 GC에 막대한 부하를 주어 프레임 드랍을 야기합니다. DSM은 이를 방지하기 위해 정교한 **지연 프록싱(Lazy-proxying)**을 수행합니다.</p><ul><li><strong>WeakMap 도입:</strong> 객체가 이미 래핑된 적이 있다면 <code>WeakMap</code>에 캐시된 Proxy 인스턴스를 즉각 반환합니다.</li><li><strong>GC 친화적 설계:</strong> 원본 객체가 메모리에서 해제될 때 프록시도 함께 <code>WeakMap</code>에서 증발하여 메모리 누수 걱정이 없습니다.</li></ul><h2 id="_2-reflect-api의-전면-도입" tabindex="-1">2. Reflect API의 전면 도입 <a class="header-anchor" href="#_2-reflect-api의-전면-도입" aria-label="Permalink to &quot;2. Reflect API의 전면 도입&quot;">​</a></h2><p>트랩 내부의 연산을 <code>target[prop]</code>으로 단순 처리하지 않고, <code>Reflect.get(target, prop, receiver)</code> API를 적극 도입했습니다. 상속 구조나 <code>this</code> 바인딩이 복잡한 도메인 객체에서 발생할 수 있는 치명적인 <strong>컨텍스트 소실(Context Loss) 버그</strong>를 완벽하게 차단합니다.</p><h2 id="_3-배열-하이재킹-array-hijacking-과-delta-계산" tabindex="-1">3. 배열 하이재킹(Array Hijacking)과 Delta 계산 <a class="header-anchor" href="#_3-배열-하이재킹-array-hijacking-과-delta-계산" aria-label="Permalink to &quot;3. 배열 하이재킹(Array Hijacking)과 Delta 계산&quot;">​</a></h2><p>얕은 복사로 <code>isMuting</code> 플래그를 조작하는 꼼수는 V8 환경에서 용납되지 않습니다. _&quot;루프 내에서 절대 객체를 동적으로 생성하거나 변이시키지 말라&quot;_는 수칙을 지키기 위해, V8 내장 배열 메서드의 동작 방식에 맞춘 수학적 Delta 알고리즘을 구현했습니다.</p><p>변경된 인덱스 범위만을 정확히 계산하여 <code>REPLACE</code> 로그를 도출하므로, 대규모 배열 조작 시에도 성능 저하가 발생하지 않습니다.</p>',10)])])}const g=e(i,[["render",c]]);export{h as __pageData,g as default};
